// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

contract HealthDataManagement {
    // 用户结构体
    struct User {
        string username;
        string hashedPassword;
        address userAddress;
        string publicKey; // 用于非对称加密
    }

    // 健康数据结构体
    struct HealthData {
        string dataHash; // 健康数据的哈希值
        string dataType; // 数据类型，如体检报告、病历等
        uint256 timestamp; // 上传时间
        string dataOwner; // 数据所有者的用户名
        string dataContent; // 数据文件的内容（原文）
        string fileName; // 文件名
    }

    // 共享权限结构体
    struct SharePermission {
        address granteeAddress; // 被授权者的地址
        string grantorUsername; // 授权者的用户名
        uint256 expirationTime; // 共享权限过期时间
    }

    // 映射用户名到用户结构体
    mapping(string => User) public users;
    // 映射用户名到健康数据数组
    mapping(string => HealthData[]) public userHealthData;
    // 映射用户名到共享权限数组
    mapping(string => SharePermission[]) public userSharePermissions;
    // 映射健康数据哈希到共享权限数组
    mapping(string => SharePermission[]) public healthDataSharePermissions;

    // 事件，用于通知前端用户注册成功
    event UserRegistered(
        string indexed username,
        string hashedPassword,
        address indexed userAddress,
        string publicKey
    );

    // 事件，用于通知前端健康数据上传成功
    event HealthDataUploaded(
        string indexed username,
        string dataHash,
        string dataType,
        uint256 timestamp
    );

    // 事件，用于通知前端共享权限设置成功
    event SharePermissionSet(
        string indexed grantorUsername,
        address indexed granteeAddress,
        string dataHash,
        uint256 expirationTime
    );

    event HealthDataDeleted(string indexed username, string dataHash);

    // 辅助变量用于跟踪用户数量和用户名索引映射
    uint256 private userCount = 0;
    mapping(uint256 => string) private userIndexToUsername;

    // 用户注册函数
    function registerUser(
        string memory _username,
        string memory _hashedPassword,
        string memory _publicKey
    ) public {
        require(bytes(users[_username].username).length == 0, "Username already exists");
        users[_username] = User({
            username: _username,
            hashedPassword: _hashedPassword,
            userAddress: msg.sender,
            publicKey: _publicKey
        });

        // 更新用户数量和用户名索引映射
        userIndexToUsername[userCount] = _username;
        userCount++;

        emit UserRegistered(_username, _hashedPassword, msg.sender, _publicKey);
    }

    // 获取所有用户名的函数
    function getAllUsernames() public view returns (string[] memory) {
        string[] memory usernames = new string[](userCount); // 使用 userCount 直接获取用户数量
        for (uint256 i = 0; i < userCount; i++) {
            usernames[i] = userIndexToUsername[i];
        }
        return usernames;
    }

    // 上传健康数据的函数
    function uploadHealthData(
        string memory _username,
        string memory _dataHash,
        string memory _dataType,
        string memory _dataContent, // 数据文件的内容（原文）
        string memory _fileName // 文件名
    ) public {
        require(keccak256(abi.encodePacked(users[_username].userAddress)) == keccak256(abi.encodePacked(msg.sender)), "Not authorized to upload data for this user");
        userHealthData[_username].push(HealthData({
            dataHash: _dataHash,
            dataType: _dataType,
            timestamp: block.timestamp,
            dataOwner: _username,
            dataContent: _dataContent,
            fileName: _fileName
        }));

        emit HealthDataUploaded(_username, _dataHash, _dataType, block.timestamp);
    }

    // 查看用户的健康数据（修改后，可查看共享数据）
    function viewHealthData(string memory _username) public view returns (HealthData[] memory) {
        address viewerAddress = msg.sender;
        HealthData[] storage healthDataList = userHealthData[_username];

        uint256 accessibleDataCount = 0;
        for (uint256 i = 0; i < healthDataList.length; i++) {
            if (keccak256(abi.encodePacked(_username)) == keccak256(abi.encodePacked(users[_username].username)) || hasPermissionViewTo(viewerAddress, healthDataList[i].dataHash)) {
                accessibleDataCount++;
            }
        }

        HealthData[] memory result = new HealthData[](accessibleDataCount);
        uint256 resultIndex = 0;

        for (uint256 i = 0; i < healthDataList.length; i++) {
            if (keccak256(abi.encodePacked(_username)) == keccak256(abi.encodePacked(users[_username].username)) || hasPermissionViewTo(viewerAddress, healthDataList[i].dataHash)) {
                result[resultIndex] = healthDataList[i];
                resultIndex++;
            }
        }

        return result;
    }

    // 新增：单独获取健康数据的内容
    function getHealthDataContent(string memory _dataHash) public view returns (string memory) {
        for (uint256 i = 0; i < userCount; i++) {
            string memory username = userIndexToUsername[i];
            for (uint256 j = 0; j < userHealthData[username].length; j++) {
                if (keccak256(abi.encodePacked(userHealthData[username][j].dataHash)) == keccak256(abi.encodePacked(_dataHash))) {
                    return userHealthData[username][j].dataContent;
                }
            }
        }
        return "";
    }

    // 新增：获取文件名的函数
    function getFileName(string memory _dataHash) public view returns (string memory) {
        // 遍历所有用户的数据，找到匹配的数据哈希
        for (uint256 i = 0; i < userCount; i++) {
            string memory username = userIndexToUsername[i];
            for (uint256 j = 0; j < userHealthData[username].length; j++) {
                if (keccak256(abi.encodePacked(userHealthData[username][j].dataHash)) == keccak256(abi.encodePacked(_dataHash))) {
                    return userHealthData[username][j].fileName;
                }
            }
        }
        return ""; // 如果未找到匹配的数据哈希，则返回空字符串
    }

    // 设置健康数据共享权限
    function setSharePermission(
        string memory _grantorUsername,
        address _granteeAddress,
        string memory _dataHash,
        uint256 _expirationTime
    ) public {
        require(keccak256(abi.encodePacked(users[_grantorUsername].userAddress)) == keccak256(abi.encodePacked(msg.sender)), "Not authorized to set permissions for this user");
        require(_expirationTime > block.timestamp, "Expiration time must be in the future");

        // Add to grantor's share permissions
        userSharePermissions[_grantorUsername].push(SharePermission({
            granteeAddress: _granteeAddress,
            grantorUsername: _grantorUsername,
            expirationTime: _expirationTime
        }));

        // Add to health data's share permissions
        healthDataSharePermissions[_dataHash].push(SharePermission({
            granteeAddress: _granteeAddress,
            grantorUsername: _grantorUsername,
            expirationTime: _expirationTime
        }));

        emit SharePermissionSet(_grantorUsername, _granteeAddress, _dataHash, _expirationTime);
    }

    // 检查用户是否有权限查看特定的健康数据
    function hasPermissionViewTo(
        address _viewerAddress,
        string memory _dataHash
    ) public view returns (bool) {
        SharePermission[] memory permissions = healthDataSharePermissions[_dataHash];
        for (uint256 i = 0; i < permissions.length; i++) {
            if (permissions[i].granteeAddress == _viewerAddress && permissions[i].expirationTime >= block.timestamp) {
                return true;
            }
        }
        return false;
    }

    // 删除健康数据
    function deleteHealthData(string memory _username, string memory _dataHash) public {
        require(keccak256(abi.encodePacked(users[_username].userAddress)) == keccak256(abi.encodePacked(msg.sender)), "Not authorized to delete data for this user");

        HealthData[] storage healthDataList = userHealthData[_username];
        for (uint256 i = 0; i < healthDataList.length; i++) {
            if (keccak256(abi.encodePacked(healthDataList[i].dataHash)) == keccak256(abi.encodePacked(_dataHash))) {
                // 删除指定索引处的健康数据
                healthDataList[i] = healthDataList[healthDataList.length - 1];
                healthDataList.pop();

                // 同时删除共享权限
                delete healthDataSharePermissions[_dataHash];

                emit HealthDataDeleted(_username, _dataHash);
                return;
            }
        }
    }
}
